"use client";

import { useState, useEffect } from "react";
import { fetchPolicyList } from "@/lib/api";
import { getInterestKeywordsQuery } from "@/lib/interestKeywords";
import type { PolicyListResponse } from "@/types";
import LoadingSpinner from "@/components/ui/LoadingSpinner";
import ErrorMessage from "@/components/ui/ErrorMessage";
import Link from "next/link";
import { Building2 } from "lucide-react";

export default function PolicyPage() {
  const [data, setData] = useState<PolicyListResponse | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const load = () => {
    setLoading(true);
    setError("");
    const keywords = getInterestKeywordsQuery();
    fetchPolicyList(1, 10, keywords || undefined)
      .then(setData)
      .catch((e) => setError(e.message))
      .finally(() => setLoading(false));
  };

  useEffect(() => { load(); }, []);

  return (
    <div className="space-y-6">
      <h1 className="text-2xl font-bold">정책 분석</h1>
      <p className="text-gray-400">정부 정책을 AI가 분석하고 수혜주를 추천합니다.</p>

      {loading && <LoadingSpinner />}
      {error && <ErrorMessage message={error} onRetry={load} />}

      {data && (
        <div className="space-y-3">
          {data.items.map((p) => (
            <Link
              key={p.id}
              href={`/policy/${p.id}`}
              className="block bg-white/5 border border-white/10 rounded-xl p-5 hover:bg-white/10 transition-colors"
            >
              <div className="flex items-start gap-4">
                <div className="bg-purple-500/20 p-2 rounded-lg shrink-0">
                  <Building2 className="w-5 h-5 text-purple-400" />
                </div>
                <div>
                  <p className="font-medium text-lg">{p.title}</p>
                  <p className="text-sm text-gray-400 mt-1">{p.department}</p>
                  <p className="text-sm text-gray-300 mt-2 line-clamp-2">{p.description}</p>
                  {p.effective_date && (
                    <p className="text-xs text-gray-500 mt-2">시행일: {p.effective_date}</p>
                  )}
                </div>
              </div>
            </Link>
          ))}
        </div>
      )}
    </div>
  );
}
